<script>
function cargarAnalistas(id_regional) {
    $.ajax({
        url: 'buscar_analistas.php',
        type: 'GET',
        data: { id_regional: id_regional },
        success: function(response) {
            $('#mostrar_analistas').html(response); // Insertar el select en el div

            // Inicializar Select2 después de cargar el select
            $('#select_analistas').select2({
                templateResult: function(option) {
                    if (!option.id) {
                        return option.text;
                    }
                    var $option = $(
                        '<div><img src="' + $(option.element).data('foto') + '" class="select2-img"/> ' + option.text + '</div>'
                    );
                    return $option;
                },
                templateSelection: function(option) {
                    if (!option.id) {
                        return option.text;
                    }
                    return $('<div><img src="' + $(option.element).data('foto') + '" class="select2-img"/> ' + option.text + '</div>');
                }
            });
        },
        error: function(xhr, status, error) {
            console.error("Error en la solicitud AJAX: " + status + error);
        }
    });
}

</script>
<script>
$(document).ready(function() {
    // Inicializar select2 (si no lo has hecho ya)
    $('#select_analistas').select2();
    
    // Variable para almacenar los analistas seleccionados
    let analistasSeleccionados = [];
    
    // Función para actualizar el campo oculto con los IDs
    function actualizarCampoOculto() {
        $('#analistas_seleccionados').val(JSON.stringify(analistasSeleccionados));
    }
    
    // Evento para el botón Adjuntar
    $('#btn-adjuntar').click(function() {
        const select = $('#select_analistas');
        const selectedOption = select.find('option:selected');
        
        if (!selectedOption.val()) {
            alert('Por favor seleccione un analista');
            return;
        }
        
        const id = selectedOption.val();
        const nombre = selectedOption.text();
        const foto = selectedOption.data('foto');
        
        // Verificar si el analista ya fue agregado
        if (analistasSeleccionados.some(a => a.id === id)) {
            alert('Este analista ya fue agregado');
            return;
        }
        
        // Agregar a la lista
        analistasSeleccionados.push({ id, nombre, foto });
        actualizarCampoOculto();
        
        // Agregar a la tabla
        const fila = `
            <tr data-id="${id}">
                <td><img src="${foto}" alt="Foto" style="width: 50px; height: 50px; object-fit: cover;"></td>
                <td>${nombre}</td>
                <td>
                    <button type="button" class="btn btn-danger btn-sm btn-eliminar">
                        <i class="bi bi-trash"></i>
                    </button>
                </td>
            </tr>
        `;
        
        $('#tabla-analistas tbody').append(fila);
    });
    
    // Evento delegado para eliminar analistas
    $('#tabla-analistas').on('click', '.btn-eliminar', function() {
        const fila = $(this).closest('tr');
        const id = fila.data('id');
        
        // Eliminar de la lista
        analistasSeleccionados = analistasSeleccionados.filter(a => a.id !== id);
        actualizarCampoOculto();
        
        // Eliminar de la tabla
        fila.remove();
    });
});
</script>
<script>
// Nuevo código JavaScript para mejorar la funcionalidad
$(document).ready(function() {
    // Cambiar estilo según prioridad seleccionada
    $('#prioridad').change(function() {
        const card = $(this).closest('.card');
        card.removeClass('priority-high priority-medium priority-low');
        
        if (this.value === 'alta') {
            card.addClass('priority-high');
        } else if (this.value === 'media') {
            card.addClass('priority-medium');
        } else if (this.value === 'baja') {
            card.addClass('priority-low');
        }
    });
    
    // Validación del formulario
    $('#formVisita').submit(function(e) {
        // Verificar que se haya seleccionado al menos un analista
        if ($('#tabla-analistas tbody tr').length === 0) {
            e.preventDefault();
            alert('Debe asignar al menos un analista para la visita');
            $('#btn-adjuntar').focus();
            return false;
        }
        
        // Validar que la fecha de visita no sea anterior a hoy
        const fechaVisita = new Date($('#fecha_visita').val());
        const hoy = new Date();
        hoy.setHours(0, 0, 0, 0);
        
        if (fechaVisita < hoy) {
            e.preventDefault();
            alert('La fecha de visita no puede ser anterior al día de hoy');
            $('#fecha_visita').focus();
            return false;
        }
    });
    
    // Mejora para el select de analistas
    $(document).on('select2:open', () => {
        document.querySelector('.select2-container--open .select2-search__field').focus();
    });
});
</script>
<!-- Campo de la institucion -->
<script>
    document.addEventListener('DOMContentLoaded', function() {
        const codigoInput = document.getElementById('codigo_i');
        const institucionInput = document.getElementById('institucion');
        
        // Variable para controlar el debounce
        let timeoutId;
        
        codigoInput.addEventListener('input', function() {
            const codigo = this.value.trim();
            
            // Limpiar el timeout anterior (debounce)
            clearTimeout(timeoutId);
            
            // Si el código está vacío, limpiar el campo institución
            if (codigo === '') {
                institucionInput.value = '';
                return;
            }
            
            // Esperar 500ms después de que el usuario deje de escribir
            timeoutId = setTimeout(() => {
                buscarInstitucion(codigo);
            }, 500);
        });
        
        function buscarInstitucion(codigo) {
            // Crear FormData para enviar los datos
            const formData = new FormData();
            formData.append('codigo', codigo);
            
            fetch('devolver_institucion.php', {
                method: 'POST',
                body: formData
            })
            .then(response => response.json())
            .then(data => {
                if (data.error) {
                    console.error('Error:', data.error);
                    institucionInput.value = 'Error en la búsqueda';
                } else {
                    institucionInput.value = data.institucion;
                    
                    // Opcional: agregar clases para estilizar según el resultado
                    if (data.institucion === 'No Registrado') {
                        institucionInput.classList.add('is-invalid');
                        institucionInput.classList.remove('is-valid');
                    } else {
                        institucionInput.classList.add('is-valid');
                        institucionInput.classList.remove('is-invalid');
                        
                        // Si tiene satélites, podríamos agregar una clase especial
                        if (data.multiple) {
                            institucionInput.classList.add('has-satellites');
                        } else {
                            institucionInput.classList.remove('has-satellites');
                        }
                    }
                }
            })
            .catch(error => {
                console.error('Error en la petición:', error);
                institucionInput.value = 'Error de conexión';
            });
        }
        
        // Opcional: limpiar el campo institución si se borra el código
        codigoInput.addEventListener('blur', function() {
            if (this.value.trim() === '') {
                institucionInput.value = '';
                institucionInput.classList.remove('is-valid', 'is-invalid', 'has-satellites');
            }
        });
    });    
</script>
